import fs from 'fs/promises';
import path from 'path';

export async function chargeCard(userId: string, tier: string): Promise<void> {
  const workspacePath = '/workspace';
  const filePath = path.join(workspacePath, 'charges.log');

  await fs.mkdir(workspacePath, { recursive: true });
  await fs.appendFile(filePath, `${userId}:${tier}\n`);
}

import {
  proxyActivities,
  defineSignal,
  defineQuery,
  setHandler,
  condition,
  sleep,
} from '@temporalio/workflow';
import type * as activities from './activities';

const { chargeCard } = proxyActivities<typeof activities>({
  startToCloseTimeout: '10 seconds',
});

export const upgradeSignal = defineSignal<[string]>('upgrade');
export const cancelSignal = defineSignal<[]>('cancel');
export const getStatusQuery = defineQuery<
  { tier: string; billings: number; cancelled: boolean }
>('getStatus');

export interface SubscriptionInput {
  userId: string;
  tier: string;
}

export interface SubscriptionOutput {
  billings: number;
  finalTier: string;
  cancelled: boolean;
}

export async function SubscriptionWorkflow(
  input: SubscriptionInput
): Promise<SubscriptionOutput> {
  let currentTier = input.tier;
  let billings = 0;
  let cancelled = false;

  setHandler(upgradeSignal, (newTier: string) => {
    currentTier = newTier;
  });

  setHandler(cancelSignal, () => {
    cancelled = true;
  });

  setHandler(getStatusQuery, () => {
    return {
      tier: currentTier,
      billings,
      cancelled,
    };
  });

  for (let i = 0; i < 12; i++) {
    if (cancelled) {
      break;
    }

    await chargeCard(input.userId, currentTier);
    billings++;

    // Wait for 2000ms or until cancelled
    await condition(() => cancelled, 2000);
  }

  return {
    billings,
    finalTier: currentTier,
    cancelled,
  };
}

import { Worker, NativeConnection } from '@temporalio/worker';
import { Connection, Client } from '@temporalio/client';
import { SubscriptionWorkflow } from './workflow';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS || 'localhost:7233';
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!runId) {
    throw new Error('ZEALT_RUN_ID is required');
  }

  // Common connection options for Temporal Cloud
  const connectionOptions = {
    address,
    tls: true,
    apiKey,
  };

  // 1. Setup Worker
  const workerConnection = await NativeConnection.connect(connectionOptions);

  const worker = await Worker.create({
    connection: workerConnection,
    namespace,
    taskQueue: 'sub-ts',
    workflowsPath: require.resolve('./workflow'),
    activities,
  });

  // Start worker in the background
  const workerPromise = worker.run();

  // 2. Setup Client
  const clientConnection = await Connection.connect(connectionOptions);
  const client = new Client({
    connection: clientConnection,
    namespace,
  });

  const workflowId = `sub-${runId}`;

  try {
    // Start workflow
    const handle = await client.workflow.start(SubscriptionWorkflow, {
      args: [{ userId: 'u1', tier: 'basic' }],
      taskQueue: 'sub-ts',
      workflowId,
    });

    // Wait 1 second of real time, send upgrade
    await new Promise(resolve => setTimeout(resolve, 1000));
    await handle.signal('upgrade', 'premium');

    // Wait 2 seconds of real time, call getStatus
    await new Promise(resolve => setTimeout(resolve, 2000));
    const status = await handle.query('getStatus');
    console.log(status);

    // Wait 2 seconds of real time, send cancel
    await new Promise(resolve => setTimeout(resolve, 2000));
    await handle.signal('cancel');

    // Await workflow's final result
    const result = await handle.result();
    console.log(`Final result: ${JSON.stringify(result)}`);
  } finally {
    worker.shutdown();
    await workerPromise;
  }
}

run().then(() => process.exit(0)).catch(err => {
  console.error(err);
  process.exit(1);
});

